css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #050a14; color: white; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 72px; height: 72px; border-bottom: 1px solid rgba(59,130,246,0.15); position: sticky; top: 0; background: rgba(5,10,20,0.9); backdrop-filter: blur(20px); z-index: 100; }
.logo { font-size: 22px; font-weight: 900; color: #3b82f6; font-family: monospace; }
.links { display: flex; gap: 28px; } .links a { color: #6b7280; text-decoration: none; font-weight: 500; transition: color 0.2s; } .links a:hover { color: #3b82f6; }
.hire { padding: 10px 22px; border-radius: 10px; border: none; background: #3b82f6; color: white; font-weight: 700; cursor: pointer; }
.hero { display: grid; grid-template-columns: 1fr 1fr; gap: 60px; align-items: center; padding: 80px 72px; min-height: calc(100vh - 72px); }
.available { display: inline-flex; align-items: center; gap: 8px; color: #22c55e; font-size: 13px; font-weight: 600; margin-bottom: 20px; } .dot { width: 8px; height: 8px; border-radius: 50%; background: #22c55e; animation: pulse 2s infinite; }
@keyframes pulse { 0%, 100% { opacity: 1; } 50% { opacity: 0.4; } }
h1 { font-size: 60px; font-weight: 900; letter-spacing: -2px; margin-bottom: 8px; }
h2 { font-size: 24px; font-weight: 600; color: #3b82f6; margin-bottom: 20px; }
.hero-left p { color: #6b7280; font-size: 16px; line-height: 1.7; margin-bottom: 28px; }
.social { display: flex; gap: 12px; margin-bottom: 20px; }
.soc-btn { padding: 10px 20px; border-radius: 10px; border: 1px solid rgba(59,130,246,0.3); color: #60a5fa; text-decoration: none; font-size: 14px; font-weight: 600; transition: all 0.2s; } .soc-btn:hover { background: rgba(59,130,246,0.1); }
.download-cv { display: inline-block; padding: 12px 24px; border-radius: 10px; background: rgba(59,130,246,0.1); color: #60a5fa; text-decoration: none; font-weight: 600; border: 1px solid rgba(59,130,246,0.2); }
.avatar-wrap { display: flex; flex-direction: column; align-items: center; margin-bottom: 28px; position: relative; }
.avatar { width: 160px; height: 160px; border-radius: 50%; background: linear-gradient(135deg, #1e3a5f, #3b82f6); display: flex; align-items: center; justify-content: center; font-size: 72px; border: 3px solid rgba(59,130,246,0.4); }
.exp-badge { position: absolute; bottom: 0; right: 60px; background: #3b82f6; color: white; padding: 6px 14px; border-radius: 20px; font-size: 12px; font-weight: 800; }
.tech-stack { display: flex; flex-wrap: wrap; gap: 10px; justify-content: center; }
.tech-stack span { padding: 8px 16px; border-radius: 8px; background: rgba(59,130,246,0.1); border: 1px solid rgba(59,130,246,0.2); color: #93c5fd; font-size: 13px; font-weight: 600; font-family: monospace; }
.skills { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.06); } .skills h2 { font-size: 42px; font-weight: 800; margin-bottom: 40px; }
.skills-grid { display: flex; flex-direction: column; gap: 20px; max-width: 700px; }
.skill-item { } .skill-name { display: flex; justify-content: space-between; font-size: 14px; margin-bottom: 8px; color: #e2e8f0; } .skill-name span:last-child { color: #3b82f6; font-weight: 700; }
.skill-bar { height: 6px; background: rgba(255,255,255,0.08); border-radius: 3px; } .skill-fill { height: 100%; border-radius: 3px; background: linear-gradient(90deg, #3b82f6, #60a5fa); }
.projects { padding: 80px 72px; border-top: 1px solid rgba(255,255,255,0.06); } .projects h2 { font-size: 42px; font-weight: 800; margin-bottom: 40px; }
.proj-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px; }
.proj-card { padding: 28px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08); transition: all 0.3s; } .proj-card:hover { border-color: rgba(59,130,246,0.4); transform: translateY(-4px); }
.proj-header { display: flex; gap: 8px; margin-bottom: 16px; }
.proj-tag { padding: 4px 10px; border-radius: 6px; background: rgba(59,130,246,0.15); color: #60a5fa; font-size: 12px; font-weight: 600; font-family: monospace; }
.proj-card h3 { font-size: 18px; font-weight: 700; margin-bottom: 8px; } .proj-card p { color: #6b7280; font-size: 14px; line-height: 1.6; margin-bottom: 20px; }
.proj-links { display: flex; gap: 16px; } .proj-links a { color: #60a5fa; text-decoration: none; font-size: 14px; font-weight: 600; }
